&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Equator &lt;/strong&gt;passes through&lt;strong&gt; 13 countries, 3 continents, and 3 water bodies&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;South America:&lt;/strong&gt; Ecuador, Colombia, Brazil&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Africa: Gabon&lt;/strong&gt;,&amp;nbsp;Congo, Democratic Republic of Congo, Uganda, Kenya, Sao Tome and Principe,&lt;strong&gt; Somalia&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Asia:&lt;/strong&gt; Maldives, Indonesia, Kiribati (Oceania).&lt;/li&gt;
