&lt;/div&gt;<br><br>&lt;p&gt;सही &lt;strong&gt;&lt;u&gt;शैल है&lt;/u&gt; ।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;शैल&amp;nbsp;&lt;/strong&gt;आमतौर पर अभिसरण प्लेट सीमाओं पर क्षेत्रीय रूपांतर द्वारा बनता है।&lt;/li&gt;
	&lt;li&gt;यह एक उच्च श्रेणी की कायांतरित चट्टान है जिसमें खनिज को तीव्र ऊष्मा और दाब के तहत पुनर्गठित किया जाता है&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;बेसाल्ट&lt;/strong&gt; एक गहरे रंग का, महीन, &lt;strong&gt;आग्नेय चट्टान है&lt;/strong&gt; जो मुख्य रूप से प्लागियोक्लेज़ और पाइरॉक्सिन खनिजों से बना है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;साइनेइट&lt;/strong&gt; एक &lt;span style=&quot;color: (37, 37, 37);  &quot;&gt;अंतर्वेधी&lt;/span&gt; आग्नेय चट्टान है जो फेल्डस्पार और फेरोमैग्नेसियन खनिज से बना है।&lt;/li&gt;
	&lt;li&gt;रासायनिक रूप से, सेनाइटिस में मध्यम मात्रा में सिलिका, अपेक्षाकृत बड़ी मात्रा में क्षार और एल्यूमिना होते हैं।&lt;/li&gt;
	&lt;li&gt;सैंडस्टोन एक अवसादी चट्टान है जो ज्यादातर क्वार्ट्ज रेत से बनी होती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सैंडस्टोन&lt;/strong&gt; जिसमें 90% से अधिक क्वार्ट्ज होते हैं उन्हें क्वार्ट्जोज सैंडस्टोन कहा जाता है।&lt;/li&gt;
	&lt;li&gt;जब बलुआ पत्थर में 25% से अधिक फेल्डस्पार होता है, तो इसे आर्कोज या आर्कोसिक सैंडस्टोन कहा जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

