				&lt;li style=&quot;line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;&quot;&gt;&lt;span&gt;&lt;span style=&quot;   font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; vertical-align: baseline; white-space-collapse: preserve;&quot;&gt;परतदार (Foliation) या अपरतदार हो सकती हैं।&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
